import json, re, sys, os

# Load books data from file
books_path = str(var_functions.query_db_28)
print('Books path:', books_path[:100])

books = []
try:
    with open(books_path, 'r') as f:
        books = json.load(f)
    print('Loaded books:', len(books))
except Exception as e:
    print('Error loading books:', e)
    books = []

# Load reviews data  
reviews_path = str(var_functions.query_db_26)
reviews = []
try:
    with open(reviews_path, 'r') as f:
        reviews = json.load(f)
    print('Loaded reviews:', len(reviews))
except Exception as e:
    print('Error loading reviews:', e)
    reviews = []

# Extract years from book details
books_processed = []
year_pattern = re.compile(r'(1[0-9]{3}|20[0-2][0-3])')

for book in books:
    book_data = book.copy()
    details = book.get('details', '')
    year = None
    if details:
        m = year_pattern.search(details)
        if m:
            year = int(m.group(1))
    book_data['year'] = year
    if year:
        book_data['decade'] = f"{year//10*10}s"
    else:
        book_data['decade'] = None
    books_processed.append(book_data)

# Map reviews to books by purchase_id
# purchase_id format: purchaseid_X, book_id format: bookid_X
valid_reviews = []
book_dict = {b['book_id']: b for b in books_processed}

for review in reviews:
    purchase_id = review.get('purchase_id', '')
    if purchase_id.startswith('purchaseid_'):
        num = purchase_id.split('_')[1]
        target_book_id = f'bookid_{num}'
        if target_book_id in book_dict:
            book = book_dict[target_book_id]
            if book['decade']:
                review_data = {
                    'book_id': target_book_id,
                    'decade': book['decade'],
                    'rating': float(review['rating'])
                }
                valid_reviews.append(review_data)

# Group by decade
decade_data = {}
for review in valid_reviews:
    decade = review['decade']
    if decade not in decade_data:
        decade_data[decade] = {'ratings': [], 'books': set()}
    decade_data[decade]['ratings'].append(review['rating'])
    decade_data[decade]['books'].add(review['book_id'])

# Filter for decades with at least 10 books and calculate avg
eligible = {}
for decade, data in decade_data.items():
    distinct_books = len(data['books'])
    total_ratings = len(data['ratings'])
    if distinct_books >= 10:
        avg = sum(data['ratings']) / total_ratings
        eligible[decade] = {
            'avg_rating': avg,
            'distinct_books': distinct_books,
            'total_ratings': total_ratings
        }
        print(f'{decade}: {avg:.2f}, books={distinct_books}, ratings={total_ratings}')

# Find best decade
best_decade = None
best_avg = 0
for decade, stats in eligible.items():
    if stats['avg_rating'] > best_avg:
        best_avg = stats['avg_rating']
        best_decade = decade

result = {
    'best_decade': best_decade,
    'best_avg': best_avg,
    'eligible_decades': eligible,
    'total_analyzed_reviews': len(valid_reviews),
    'total_books_with_years': len([b for b in books_processed if b['year']])
}

print('__RESULT__:')
print(json.dumps(result, default=str))

